import json

# Load trade data
files = [
    locals()['var_function-call-644896174313076635'],
    locals()['var_function-call-12606861803556003272'],
    locals()['var_function-call-15693352361615473574']
]

all_trades = []
for fpath in files:
    with open(fpath, 'r') as f:
        all_trades.extend(json.load(f))

# Load stock info
info_file = locals()['var_function-call-3475565856532032649']
with open(info_file, 'r') as f:
    stock_info = json.load(f)

# Create a map for Symbol -> Name
def extract_name(desc):
    # Heuristic: Name is usually the first part before " is", " specializes", " provides", " operates", " offers"
    # But some descriptions are just the name.
    # Let's split by common verbs.
    verbs = [" is ", " specializes ", " provides ", " offers ", " operates ", " focuses ", " engages ", " excels ", " generates "]
    min_idx = len(desc)
    for v in verbs:
        idx = desc.find(v)
        if idx != -1 and idx < min_idx:
            min_idx = idx
    if min_idx != len(desc):
        return desc[:min_idx].strip()
    return desc.strip()

sym_to_name = {item['Symbol']: extract_name(item['Company Description']) for item in stock_info}

# Process trades
from collections import defaultdict
stats = defaultdict(lambda: {'up': 0, 'down': 0})

for trade in all_trades:
    sym = trade['Symbol']
    try:
        op = float(trade['Open'])
        cl = float(trade['Close'])
        if cl > op:
            stats[sym]['up'] += 1
        elif cl < op:
            stats[sym]['down'] += 1
    except:
        continue

# Filter and sort
candidates = []
for sym, counts in stats.items():
    if counts['up'] > counts['down']:
        candidates.append({
            'Symbol': sym,
            'Up': counts['up'],
            'Down': counts['down'],
            'Name': sym_to_name.get(sym, sym)
        })

# Sort by Up days descending
top_5 = sorted(candidates, key=lambda x: x['Up'], reverse=True)[:5]

print("__RESULT__:")
print(json.dumps(top_5))

